const event = $input.first().json.body;
const type = event.type;
const user = event.user_name || 'Investor';
const amount = event.amount || '0';
const property = event.property || '';

const templates = {
  'purchase_confirmed': `Hi ${user}, your investment of $${amount} in ${property} is confirmed! Your shares are now in your portfolio.`,
  'rent_available': `Hi ${user}, you have $${amount} rental income available to claim from ${property}.`,
  'rent_claimed': `Hi ${user}, your claim of $${amount} has been submitted. Bank transfers process every Tuesday.`,
  'commission_earned': `Hi ${user}, you earned $${amount} commission! It will be claimable in 14 days.`,
  'commission_claimable': `Hi ${user}, your $${amount} commission is now ready to claim.`,
  'payout_completed': `Hi ${user}, your payout of £${amount} has been sent to your bank account ✅`,
  'payout_failed': `⚠️ Payout of £${amount} failed for ${user}. Please check Revolut dashboard.`,
  'proposal_created': `New proposal for ${property}: ${event.title || 'View details'}. Vote now on NFsTay.`,
  'proposal_result': `Proposal for ${property} has been ${event.result || 'decided'}. View results on NFsTay.`,
  'bank_details_saved': `Hi ${user}, your bank details have been saved for NFsTay payouts. If you didn't do this, contact us immediately.`,
  'batch_ready': `NFsTay Payout Batch Ready ✅\nPayees: ${event.count || 0}\nGBP: £${event.gbp_total || 0}\nEUR: €${event.eur_total || 0}\n\n👉 Open Revolut app to approve with Face ID.`
};

const message = templates[type] || `NFsTay notification: ${type}`;
const isAdmin = type === 'payout_failed' || type === 'batch_ready';

return [{ json: { message, type, isAdmin, email: event.email, phone: event.phone } }];
